class Solution:
    def hIndex(self, citations):
        n = len(citations)
        # Independent definition scan: h is the count of values >= some k,
        # so test every candidate h from n down and take the first that holds.
        for h in range(n, -1, -1):
            if sum(1 for c in citations if c >= h) >= h:
                return h
        return 0

