var hIndex = function(citations) {
    const n = citations.length;
    const buckets = new Array(n + 1).fill(0);
    for (const c of citations) buckets[Math.min(c, n)]++;
    let total = 0;
    for (let h = n; h >= 0; h--) {
        total += buckets[h];
        if (total >= h) return h;
    }
    return 0;
};
